INSERT INTO dnddb_armors (id, source_book_id, page, amount, currency_type, description, name, weight, armor_class, stealth_disadvantage, strength_requirement, type) VALUES (75, 25, 144, 5, 'GOLD', 'Padded armor consists of quilted layers of cloth and batting.', 'Padded Armor', 8, 11, true, null, 'LIGHT_ARMOR'),
                                                                                                                                                                            (76, 25, 144, 10, 'GOLD', 'The breastplate and shoulder protectors of this armor are made of leather that has been stiffened by being boiled in oil. The rest of the armor is made of softer and more flexible materials.', 'Leather Armor', 10, 11, false, null, 'LIGHT_ARMOR'),
                                                                                                                                                                            (77, 25, 144, 45, 'GOLD', 'Made from tough but flexible leather, studded leather is reinforced with close-set rivets or spikes.', 'Studded Leather Armor', 13, 12, false, null, 'LIGHT_ARMOR'),
                                                                                                                                                                            (78, 25, 144, 10, 'GOLD', 'This crude armor consists of thick furs and pelts. It is commonly worn by barbarian tribes, evil humanoids, and other folk who lack access to the tools and materials needed to create better armor.', 'Hide Armor', 12, 12, false, null, 'MEDIUM_ARMOR'),
                                                                                                                                                                            (79, 25, 144, 50, 'GOLD', 'Made of interlocking metal rings, a chain shirt is worn between layers of clothing or leather. This armor offers modest protection to the wearer''s upper body and allows the sound of the rings rubbing against one another to be muffled by outer layers.', 'Chain Shirt', 20, 13, false, null, 'MEDIUM_ARMOR'),
                                                                                                                                                                            (80, 25, 144, 50, 'GOLD', 'This armor consists of a coat and leggings (and perhaps a separate skirt) of leather covered with overlapping pieces of metal, much like the scales of a fish. The suit includes gauntlets.', 'Scale Mail', 45, 14, true, null, 'MEDIUM_ARMOR'),
                                                                                                                                                                            (81, 28, 121, 75, 'GOLD', 'Spiked armor is a rare type of medium armor made by dwarves. It consists of a leather coat and leggings covered with spikes that are usually made of metal.', 'Spiked Armor', 45, 14, true, null, 'MEDIUM_ARMOR'),
                                                                                                                                                                            (82, 25, 145, 400, 'GOLD', 'This armor consists of a fitted metal chest piece worn with supple leather. Although it leaves the legs and arms relatively unprotected, this armor provides good protection for the wearer''s vital organs while leaving the wearer relatively unencumbered.', 'Breastplate', 20, 14, false, null, 'MEDIUM_ARMOR'),
                                                                                                                                                                            (83, 25, 145, 750, 'GOLD', 'Half plate consists of shaped metal plates that cover most of the wearer''s body. It does not include leg protection beyond simple greaves that are attached with leather straps.', 'Half Plate Armor', 40, 15, true, null, 'MEDIUM_ARMOR'),
                                                                                                                                                                            (84, 25, 145, 30, 'GOLD', 'This armor is leather armor with heavy rings sewn into it. The rings help reinforce the armor against blows from swords and axes. Ring mail is inferior to chain mail, and it''s usually worn only by those who can''t afford better armor.', 'Ring Mail', 40, 14, true, null, 'HEAVY_ARMOR'),
                                                                                                                                                                            (85, 25, 145, 75, 'GOLD', 'Made of interlocking metal rings, chain mail includes a layer of quilted fabric worn underneath the mail to prevent chafing and to cushion the impact of blows. The suit includes gauntlets.', 'Chain Mail', 55, 16, true, 13, 'HEAVY_ARMOR'),
                                                                                                                                                                            (86, 25, 145, 200, 'GOLD', 'This armor is made of narrow vertical strips of metal riveted to a backing of leather that is worn over cloth padding. Flexible chain mail protects the joints.', 'Splint Armor', 60, 17, true, 15, 'HEAVY_ARMOR'),
                                                                                                                                                                            (87, 25, 145, 1500, 'GOLD', 'Plate consists of shaped, interlocking metal plates to cover the entire body. A suit of plate includes gauntlets, heavy leather boots, a visored helmet, and thick layers of padding underneath the armor. Buckles and straps distribute the weight over the body.', 'Plate Armor', 65, 18, true, 15, 'HEAVY_ARMOR'),
                                                                                                                                                                            (88, 25, 144, 10, 'GOLD', 'A shield is made from wood or metal and is carried in one hand. Wielding a shield increases your Armor Class by 2. You can benefit from only one shield at a time.', 'Shield', 6, 2, false, null, 'SHIELD');
INSERT INTO dnddb_races (id, name, description, age, alignment, size, speed, source_book_id, page, type, size_type) VALUES (51, 'Dragonborn', ' Born of dragons, as their name proclaims, the dragonborn walk proudly through a world that greets them with fearful incomprehension. Shaped by draconic gods or the dragons themselves, dragonborn originally hatched from dragon eggs as a unique race, combining the best attributes of dragons and humanoids. Some dragonborn are faithful servants to true dragons, others form the ranks of soldiers in great wars, and still others find themselves adrift, with no clear calling in life.',
                                                                                                                            'Young dragonborn grow quickly. They walk hours after hatching, attain the size and development of a 10-year-old human child by the age of 3, and reach adulthood by 15. They live to be around 80.',
                                                                                                                            'Dragonborn tend towards extremes, making a conscious choice for one side or the other between Good and Evil (represented by Bahamut and Tiamat, respectively). More side with Bahamut than Tiamat (whose non-dragon followers are mostly kobolds), but villainous dragonborn can be quite terrible indeed. Some rare few choose to devote themselves to lesser dragon deities, such as Chronepsis (Neutral), and fewer still choose to worship Io, the Ninefold Dragon, who is all alignments at once.',
                                                                                                                            'Dragonborn are taller and heavier than humans, standing well over 6 feet tall and averaging almost 250 pounds.',
                                                                                                                            30, 25, 32, 'COMMON', 'MEDIUM'),
                                                                                                                           (52, 'Dwarf', 'Kingdoms rich in ancient grandeur, halls carved into the roots of mountains, the echoing of picks and hammers in deep mines and blazing forges, a commitment to clan and tradition, and a burning hatred of goblins and orcs—these common threads unite all dwarves.',
                                                                                                                            'Dwarves mature at the same rate as humans, but they''re considered young until they reach the age of 50. On average, they live about 350 years.',
                                                                                                                            'Most dwarves are lawful, believing firmly in the benefits of a well-ordered society. They tend toward good as well, with a strong sense of fair play and a belief that everyone deserves to share in the benefits of a just order.',
                                                                                                                            'Dwarves stand between 4 and 5 feet tall and average about 150 pounds.',
                                                                                                                            30, 25, 18, 'COMMON', 'MEDIUM'),
                                                                                                                           (53, 'Elf', 'Elves are a magical people of otherworldly grace, living in the world but not entirely part of it. They live in places of ethereal beauty, in the midst of ancient forests or in silvery spires glittering with faerie light, where soft music drifts through the air and gentle fragrances waft on the breeze. Elves love nature and magic, art and artistry, music and poetry, and the good things of the world.',
                                                                                                                            'Although elves reach physical maturity at about the same age as humans, the elven understanding of adulthood goes beyond physical growth to encompass worldly experience. An elf typically claims adulthood and an adult name around the age of 100 and can live to be 750 years old.',
                                                                                                                            'Elves love freedom, variety, and self-expression, so they lean strongly towards the gentler aspects of chaos. They value and protect others'' freedom as well as their own, and are good more often than not. Drow are an exception; their exile into the Underdark has made them vicious and dangerous. Drow are more often evil than not.',
                                                                                                                            'Elves range from under 5 to over 6 feet tall and have slender builds.',
                                                                                                                            30, 25, 21, 'COMMON', 'MEDIUM'),
                                                                                                                           (54, 'Gnome', 'A constant hum of busy activity pervades the warrens and neighborhoods where gnomes form their close-knit communities. Louder sounds punctuate the hum: a crunch of grinding gears here, a minor explosion there, a yelp of surprise or triumph, and especially bursts of laughter. Gnomes take delight in life, enjoying every moment of invention, exploration, investigation, creation, and play.',
                                                                                                                            'Gnomes mature at the same rate as humans, and most are expected to settle into adult life around the age of 40. They can live to 350 years on average, but it''s not too uncommon for them to reach 500 years of age.',
                                                                                                                            'Gnomes are generally Good. Those who tend towards Law are sages, engineers, researchers, scholars, investigators, or inventors. Those who tend towards Chaos are often minstrels, tricksters, wanderers, or fanciful jewelers. Gnomes are light-hearted, and even the tricksters amongst them favor harmless pranks over vicious schemes.',
                                                                                                                            'Gnomes are between 3 and 4 feet tall and weigh around 40 pounds.',
                                                                                                                            25, 25, 35, 'COMMON', 'SMALL'),
                                                                                                                           (55, 'Half-Elf', 'Walking in two worlds but truly belonging to neither, half-elves combine what some say are the best qualities of their elf and human parents: human curiosity, inventiveness, and ambition tempered by the refined senses, love of nature, and artistic tastes of the elves. Some half-elves live among humans, set apart by their emotional and physical differences, watching friends and loved ones age while time barely touches them. Others live with the elves, growing restless as they reach adulthood in the timeless elven realms, while their peers continue to live as children. Many half-elves, unable to fit into either society, choose lives of solitary wandering or join with other misfits and outcasts in the adventuring life.',
                                                                                                                            'Half-elves age at much the same rate as humans, reaching adulthood at the age of 20. They live much longer than humans, however, often exceeding 180 years.',
                                                                                                                            'Half-elves share the chaotic bent of their elven heritage. They both value personal freedom and creative expression, demonstrating neither love of leaders nor desire for followers. They chafe at rules, resent others'' demands, and sometimes prove unreliable, or at least unpredictable. They are good and evil in equal numbers, a trait they share with their human parents.',
                                                                                                                            'Half-elves are more or less the same size as humans, ranging from 5 to 6 feet tall.',
                                                                                                                            30, 25, 38, 'COMMON', 'MEDIUM'),
                                                                                                                           (56, 'Half-Orc', 'Whether united under the leadership of a mighty warlock or having fought to a standstill after years of conflict, orc and human communities, sometimes form alliances. When these alliances are sealed by marriages, half-orcs are born. Some half-orcs rise to become proud leaders of orc communities. Some venture into the world to prove their worth. Many of these become adventurers, achieving greatness for their mighty deeds.',
                                                                                                                            'Half-orcs mature a little faster than humans, reaching adulthood around age 14. They age noticeably faster and rarely live longer than 75 years.',
                                                                                                                            'Half-orcs inherit a tendency toward chaos from their orc parents and are not strongly inclined toward good. Half-orcs raised among orcs and willing to live out their lives among them are usually evil.',
                                                                                                                            'Half-orcs are somewhat larger and bulkier than humans, and they range from 5 to well over 6 feet tall.',
                                                                                                                            30, 25, 40, 'COMMON', 'MEDIUM'),
                                                                                                                           (57, 'Halfling', 'The comforts of home are the goals of most halflings’ lives: a place to settle in peace and quiet, far from marauding monsters and clashing armies; a blazing fire and a generous meal; fine drink and fine conversation. Though some halflings live out their days in remote agricultural communities, others form nomadic bands that travel constantly, lured by the open road and the wide horizon to discover the wonders of new lands and peoples. But even these wanderers love peace, food, hearth, and home, though home might be a wagon jostling along a dirt road or a raft floating downriver.',
                                                                                                                            'A halfling reaches adulthood at the age of 20 and generally lives into the middle of his or her second century.',
                                                                                                                            'Most halflings are lawful good. As a rule, they are good-hearted and kind, hate to see others in pain, and have no tolerance for oppression. They are also very orderly and traditional, leaning heavily on the support of their community and the comfort of the old ways.',
                                                                                                                            'Halflings average about 3 feet tall and weigh about 40 pounds.',
                                                                                                                            25, 25, 26, 'COMMON', 'SMALL'),
                                                                                                                           (58, 'Human', 'In the reckonings of most worlds, humans are the youngest of the common races, late to arrive on the world scene and short-lived in comparison to dwarves, elves, and dragons. Perhaps it is because of their shorter lives that they strive to achieve as much as they can in the years they are given. Or maybe they feel they have something to prove to the elder races, and that''s why they build their mighty empires on the foundation of conquest and trade. Whatever drives them, humans are the innovators, the achievers, and the pioneers of the worlds.',
                                                                                                                            'Humans reach adulthood in their late teens and live less than a century.',
                                                                                                                            'Humans tend toward no particular alignment. The best and the worst are found among them.',
                                                                                                                            'Humans vary widely in height and build, from barely 5 feet to well over 6 feet tall.',
                                                                                                                            30, 25, 29, 'COMMON', 'MEDIUM'),
                                                                                                                           (59, 'Tiefling', 'To be greeted with stares and whispers, to suffer violence and insult on the street, to see mistrust and fear in every eye: this is the lot of the tiefling. And to twist the knife, tieflings know that this is because a pact struck generations ago infused the essence of Asmodeus—overlord of the Nine Hells—into their bloodline. Their appearance and their nature are not their fault but the result of an ancient sin, for which they and their children and their children’s children will always be held accountable.',
                                                                                                                            'Tieflings mature at the same rate as humans but live a few years longer.',
                                                                                                                            'Tieflings might not have an innate tendency toward evil, but many of them end up there. Evil or not, an independent nature inclines many tieflings toward a chaotic alignment.',
                                                                                                                            'Tieflings are about the same size and build as humans.',
                                                                                                                            30, 25, 42, 'COMMON', 'MEDIUM');
INSERT INTO dnddb_classes (id, name, description, hit_dice, proficiency_count, soruce_book_id, page) VALUES (91, 'Barbarian', 'For some, their rage springs from a communion with fierce animal spirits. Others draw from a roiling reservoir of anger at a world full of pain. For every barbarian, rage is a power that fuels not just a battle frenzy but also uncanny reflexes, resilience, and feats of strength.',
                                                                                                             12, 2, 25, 46),
                                                                                                            (92, 'Bard', 'Whether scholar, skald, or scoundrel, a bard weaves magic through words and music to inspire allies, demoralize foes, manipulate minds, create illusions, and even heal wounds. The bard is a master of song, speech, and the magic they contain.',
                                                                                                             8, 3, 25, 51),
                                                                                                            (93, 'Cleric', 'Clerics are intermediaries between the mortal world and the distant planes of the gods. As varied as the gods they serve, clerics strive to embody the handiwork of their deities. No ordinary priest, a cleric is imbued with divine magic.',
                                                                                                             8, 2, 25, 56),
                                                                                                            (94, 'Druid', 'Whether calling on the elemental forces of nature or emulating the creatures of the animal world, druids are an embodiment of nature''s resilience, cunning, and fury. They claim no mastery over nature, but see themselves as extensions of nature''s indomitable will.',
                                                                                                             8, 2, 25, 64),
                                                                                                            (95, 'Fighter', 'Fighters share an unparalleled mastery with weapons and armor, and a thorough knowledge of the skills of combat. They are well acquainted with death, both meting it out and staring it defiantly in the face.',
                                                                                                             10, 2, 25, 72),
                                                                                                            (96, 'Monk', 'Monks are united in their ability to magically harness the energy that flows in their bodies. Whether channeled as a striking display of combat prowess or a subtler focus of defensive ability and speed, this energy infuses all that a monk does.',
                                                                                                             8, 2, 25, 76),
                                                                                                            (97, 'Paladin', 'Whether sworn before a god''s altar and the witness of a priest, in a sacred glade before nature spirits and fey beings, or in a moment of desperation and grief with the dead as the only witness, a paladin''s oath is a powerful bond.',
                                                                                                             10, 2, 25, 82),
                                                                                                            (98, 'Ranger', 'Far from the bustle of cities and towns, past the hedges that shelter the most distant farms from the terrors of the wild, amid the dense-packed trees of trackless forests and across wide and empty plains, rangers keep their unending watch.',
                                                                                                             10, 3, 25, 89),
                                                                                                            (99, 'Rogue', 'Rogues rely on skill, stealth, and their foes'' vulnerabilities to get the upper hand in any situation. They have a knack for finding the solution to just about any problem, demonstrating a resourcefulness and versatility that is the cornerstone of any successful adventuring party.',
                                                                                                             8, 4, 25, 94),
                                                                                                            (100, 'Sorcerer', 'Sorcerers carry a magical birthright conferred upon them by an exotic bloodline, some otherworldly influence, or exposure to unknown cosmic forces. No one chooses sorcery; the power chooses the sorcerer.',
                                                                                                             6, 2, 25, 99),
                                                                                                            (101, 'Warlock', 'Warlocks are seekers of the knowledge that lies hidden in the fabric of the multiverse. Through pacts made with mysterious beings of supernatural power, warlocks unlock magical effects both subtle and spectacular.',
                                                                                                             8, 2, 25, 105),
                                                                                                            (102, 'Wizard', 'Wizards are supreme magic-users, defined and united as a class by the spells they cast. Drawing on the subtle weave of magic that permeates the cosmos, wizards cast spells of explosive fire, arcing lightning, subtle deception, brute-force mind control, and much more.',
                                                                                                             6, 2, 25, 112);
